function calc_be_17a(document) {
    const F6 = document.field1;
    const F7 = document.field2;
    const F8 = document.field3;
    const F10 = document.field4;
    const F11 = document.field5;
    const F15 = document.field7;
    const F16 = document.field8;
    const F17 = document.field9;
    const F18 = document.field10;
    const F19 = document.field11;
    const F20 = document.field12;	
    const F21 = document.field13;
    const F22 = document.field14;
    const F23 = document.field15;

    let F13 = 0;
    switch (document.field6) {
        case 'Default Value':
            F13 =
                Math.abs(F15 * (1 - F16 / 100) + F17 * F15) *
                Math.abs((1 - F18) / F19) *
                F20;
            break;
        case 'Adjust Default Value':
            F13 = (F21 / F22) * F23 * F20;
            break;
    }
    document.field18 = isFinite(F13) ? F13 : 0;
    const F12 = isFinite(F13) ? F13 : 0;

    const F9 = F10 * (F11 / 365);
    document.field17 = F9;
