function get_methane_correction(value) {
    switch (value) {
        case 'Discharge of wastewater to sea, river or lake':
            return 0.1;
        case 'Land application':
            return 0.1;
        case 'Aerobic treatment, well managed':
            return 0;
        case 'Aerobic treatment, poorly managed or overloaded':
            return 0.3;
        case 'Anaerobic digester for sludge without methane recovery':
            return 0.8;
        case 'Anaerobic reactor without methane recover':
            return 0.8;
        case 'Anaerobic shallow lagoon (depth less than 2 metres)':
            return 0.2;
        case 'Anaerobic deep lagoon (depth more than 2 metres)':
            return 0.8;
        case 'Septic system':
            return 0.5;
        default:
            throw new Error('Unknown option: ' + value);
    }
}

